const fs = global.get('fs');
const QUEUE_PATH = '/data/retry_queue.json';
const MAX_RETRIES = 5;
const pool = global.get('pgPool');
if (msg.payload !== 'drain') return null;
if (!pool) { node.warn('Retry: pgPool not available'); return null; }
fs.readFile(QUEUE_PATH, 'utf8', function(readErr, data) {
    if (readErr || !data) return;
    let queue = [];
    try { queue = JSON.parse(data); } catch(e) { return; }
    if (queue.length === 0) return;
    const entry = queue.shift();
    entry.retries++;
    if (entry.retries > MAX_RETRIES) {
        node.warn('Retry: dropped after ' + MAX_RETRIES + ' attempts');
        fs.writeFile(QUEUE_PATH, JSON.stringify(queue), 'utf8', function(){});
        return;
    }
    if (entry.sql && entry.params) {
        pool.query(entry.sql, entry.params, function(err) {
            if (err) {
                node.error('Retry [' + entry.retries + '/' + MAX_RETRIES + '] failed: ' + err.message);
                queue.unshift(entry);
            } else {
                node.log('Retry [' + entry.retries + '/' + MAX_RETRIES + '] ok: ' + entry.count + ' rows');
            }
            fs.writeFile(QUEUE_PATH, JSON.stringify(queue), 'utf8', function(){});
        });
    } else {
        node.warn('Retry: entry has no sql/params, skipping');
        fs.writeFile(QUEUE_PATH, JSON.stringify(queue), 'utf8', function(){});
    }
});
return null;

